import React, { useEffect, useState } from "react";
import {
  Box,
  Button,
  Typography,
  Card,
  CardContent,
  Divider,
  CircularProgress,
} from "@mui/material";
import { Link as RouterLink } from "react-router-dom";
import Footer from "../../components/Footer";

interface Novedad {
  IdNovedad: number;
  IdEmpleado: number;
  Descripcion: string;
  Fecha: string;
}

export default function Tablon() {
  const [novedades, setNovedades] = useState<Novedad[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchNovedades = async () => {
      try {
        const res = await fetch("http://localhost:4000/tablon");
        const data = await res.json();
        setNovedades(data);
      } catch (err) {
        setNovedades([]);
      } finally {
        setLoading(false);
      }
    };
    fetchNovedades();
  }, []);

  return (
    <Box
      sx={{
        minHeight: "100vh",
        backgroundColor: "#ECEFF1",
        display: "flex",
        flexDirection: "column",
      }}
    >
      {/* Encabezado */}
      <Box
        sx={{
          py: 4,
          px: 3,
          backgroundColor: "#1c1c1c",
          boxShadow: "0 2px 8px rgba(0, 0, 0, 0.3)",
        }}
      >
        <Typography
          variant="h3"
          sx={{
            fontFamily: "Tektur, sans-serif",
            fontWeight: 700,
            color: "#ffffff",
            userSelect: "none",
          }}
        >
          <span style={{ color: "#FF6B00" }}>360</span>{" "}
          <span style={{ color: "#ffffff" }}>Sueldos</span>
        </Typography>
      </Box>

      {/* Botón Volver */}
      <Box sx={{ display: "flex", justifyContent: "flex-end", mt: 3, px: 4 }}>
        <Button
          component={RouterLink}
          to="/rrhh-principal"
          variant="contained"
          sx={{
            backgroundColor: "#1565C0",
            marginRight: 3,
            color: "#ffffff",
            width: 180,
            letterSpacing: 3,
            fontSize: 20,
            borderRadius: 3,
            mr: 5,
            fontFamily: "Tektur, sans-serif",
            fontWeight: 500,
            textTransform: "none",
          }}
        >
          Volver
        </Button>
      </Box>

      {/* Tarjetas de mensajes */}
      <Box
        sx={{
          flexGrow: 1,
          px: 3,
          mt: 4,
          display: "flex",
          flexDirection: "column",
          gap: 4,
          maxWidth: "900px",
          mx: "auto",
          mb: 6,
        }}
      >
        {loading ? (
          <Box sx={{ textAlign: "center", mt: 8 }}>
            <CircularProgress />
          </Box>
        ) : novedades.length === 0 ? (
          <Typography
            variant="h6"
            sx={{
              fontFamily: "Tektur, sans-serif",
              color: "#888",
              textAlign: "center",
              mt: 8,
            }}
          >
            No hay novedades publicadas.
          </Typography>
        ) : (
          novedades.map((mensaje) => (
            <Card
              key={mensaje.IdNovedad}
              sx={{
                borderRadius: 3,
                backgroundColor: "#ffffff",
                boxShadow: "0 6px 20px rgba(0, 0, 0, 0.08)",
                transition: "transform 0.2s ease, box-shadow 0.2s ease",
                "&:hover": {
                  transform: "translateY(-2px)",
                  boxShadow: "0 12px 24px rgba(0,0,0,0.12)",
                },
              }}
            >
              <CardContent>
                <Typography
                  variant="h6"
                  sx={{
                    fontFamily: "Tektur, sans-serif",
                    color: "#fff",
                    fontWeight: 600,
                    background: "linear-gradient(90deg, #478FED, #1976d2)",
                    borderRadius: 2,
                    padding: "6px 12px",
                    letterSpacing: 1.5,
                    mb: 2,
                    display: "inline-block",
                  }}
                >
                  {/* Puedes mostrar el IdEmpleado o un título fijo */}
                  Novedad de Empleado #{mensaje.IdEmpleado}
                </Typography>

                <Divider sx={{ mb: 2 }} />

                <Typography
                  variant="body1"
                  sx={{
                    fontFamily: "Tektur, sans-serif",
                    color: "#555",
                    lineHeight: 1.6,
                  }}
                >
                  {mensaje.Descripcion}
                </Typography>

                <Typography
                  variant="caption"
                  sx={{
                    display: "block",
                    textAlign: "right",
                    mt: 2,
                    color: "#999",
                    fontFamily: "Tektur, sans-serif",
                  }}
                >
                  Publicado el{" "}
                  {new Date(mensaje.Fecha).toLocaleString()}
                </Typography>
              </CardContent>
            </Card>
          ))
        )}
      </Box>

      <Footer />
    </Box>
  );
}
